#include <stdio.h>
#include <stdlib.h>

int main(){
    int N,K;
    scanf("%d%d",&N,&K);

    long long *freq=calloc(K,sizeof(long long));
    freq[0]=1;

    long long prefix=0,ans=0;

    for(int i=0;i<N;i++){
        long long x;
        scanf("%lld",&x);

        prefix=(prefix+x)%K;
        if(prefix<0) prefix+=K;

        ans+=freq[prefix];
        freq[prefix]++;
    }

    printf("%lld",ans);
}

code.Java:
import java.util.*;
import java.io.*;

class Codechef
{
    public static void main (String[] args) throws Exception
    {
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        String[] first=br.readLine().split(" ");
        int N=Integer.parseInt(first[0]);
        int K=Integer.parseInt(first[1]);

        long[] freq=new long[K];
        freq[0]=1;

        long prefix=0,ans=0;

        String[] arr=br.readLine().split(" ");

        for(int i=0;i<N;i++){
            long x=Long.parseLong(arr[i]);
            prefix=(prefix+x)%K;
            if(prefix<0) prefix+=K;

            ans+=freq[(int)prefix];
            freq[(int)prefix]++;
        }

        System.out.print(ans);
    }
}
